trigger.body:

  v_DateFrom DATE;
  v_DateTo DATE;
  v_DateNoCalculate DATE;

  v_PeriodFromID character varying(32); --OBTG:VARCHAR2--
  v_PeriodToID character varying(32);   --OBTG:VARCHAR2--
  v_PeriodNotID character varying(32);  --OBTG:VARCHAR2--
  v_Message character varying(60);   	       --OBTG:VARCHAR2--

BEGIN



    IF AD_isTriggerEnabled()='N' THEN RETURN;
    END IF;

    IF (UPDATING OR INSERTING) THEN

		v_PeriodNotID:= :NEW.c_period_id;

		select c_periodfrom_id, c_periodto_id
		INTO v_PeriodFromID, v_PeriodToID
		from ssmrps_asimulation_prod where ssmrps_asimulation_prod_id = :NEW.ssmrps_asimulation_prod_id;



		-- Get Date From
		select coalesce((select TO_DATE(startdate) from c_period where c_period_id = v_PeriodFromID),null)
		into v_DateFrom
		from dual;

		-- Get Date to
		select coalesce((select TO_DATE(enddate) from c_period where c_period_id = v_PeriodToID),null)
		into v_DateTo
		from dual;


		-- Get Date to
		select coalesce((select TO_DATE(enddate) from c_period where c_period_id = v_PeriodNotID),null)
		into v_DateNoCalculate
		from dual;


		--RAISE_APPLICATION_ERROR(-20000, '@Error en los filtros de fecha.@') ;


		select
		(case when (v_DateNoCalculate > fechai) AND (v_DateNoCalculate < fechaf)  then 'Sucess'
			else 'Error'
		end) as mensaje 
		INTO v_Message
		from
		(
			select 
			v_DateFrom as fechai,
			v_DateTo as fechaf
			from dual
		) validDate;

		IF (v_Message='Error') THEN
			RAISE_APPLICATION_ERROR(-20000, '@Ssmrps_ValidateNoDates@') ;
		END IF;



    END IF;

END SSMRPS_NOVALIDATEPERIODS_TRG
